// nodes/textNode.js
import { useState, useEffect, useRef } from 'react';
import { BaseNode, fieldStyle } from './BaseNode';
import { useStore } from '../store';
import { Handle, Position } from 'reactflow';

// Extract all {{ variable }} names from text
const extractVars = (text) => {
  const regex = /\{\{\s*([a-zA-Z_$][a-zA-Z0-9_$]*)\s*\}\}/g;
  const vars = [];
  let match;
  while ((match = regex.exec(text)) !== null) {
    if (!vars.includes(match[1])) vars.push(match[1]);
  }
  return vars;
};

export const TextNode = ({ id, data }) => {
  const updateNodeField = useStore((s) => s.updateNodeField);
  const [text, setText] = useState(data?.text ?? '{{input}}');
  const [vars, setVars] = useState(() => extractVars(data?.text ?? '{{input}}'));
  const textareaRef = useRef(null);

  const accentColor = '#f59e0b';

  const handleChange = (e) => {
    const val = e.target.value;
    setText(val);
    updateNodeField(id, 'text', val);
    setVars(extractVars(val));
  };

  // Auto-resize textarea
  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = textareaRef.current.scrollHeight + 'px';
    }
  }, [text]);

  // Calculate dynamic width based on longest line
  const lines = text.split('\n');
  const longestLine = Math.max(...lines.map((l) => l.length), 10);
  const dynamicWidth = Math.min(Math.max(longestLine * 8 + 60, 220), 600);

  return (
    <BaseNode
      id={id}
      title="Text"
      icon="✏️"
      accentColor={accentColor}
      outputs={[{ id: 'output', label: 'output' }]}
      minWidth={dynamicWidth}
    >
      {/* Dynamic variable handles (rendered outside BaseNode handles) */}
      {vars.map((v, i) => {
        const top = vars.length === 1
          ? 50
          : 20 + (i / (vars.length - 1)) * 60;
        return (
          <div key={v} style={{ position: 'absolute', left: 0, top: `${top}%`, transform: 'translateY(-50%)' }}>
            <Handle
              type="target"
              position={Position.Left}
              id={`var-${v}`}
              style={{
                left: -6,
                width: 12,
                height: 12,
                background: accentColor,
                border: '2px solid #1a1f2e',
                borderRadius: '50%',
              }}
            />
            <span
              style={{
                position: 'absolute',
                left: 10,
                top: '50%',
                transform: 'translateY(-50%)',
                fontSize: '9px',
                color: 'rgba(255,255,255,0.4)',
                whiteSpace: 'nowrap',
                pointerEvents: 'none',
              }}
            >
              {v}
            </span>
          </div>
        );
      })}

      <div style={fieldStyle.group}>
        <label style={fieldStyle.label}>Text</label>
        <textarea
          ref={textareaRef}
          style={{
            ...fieldStyle.input,
            resize: 'none',
            overflow: 'hidden',
            minHeight: '60px',
            lineHeight: '1.5',
            fontFamily: "'JetBrains Mono', 'Fira Code', monospace",
            fontSize: '12px',
          }}
          value={text}
          onChange={handleChange}
          rows={1}
        />
      </div>
      {vars.length > 0 && (
        <div style={{ fontSize: '10px', color: 'rgba(255,255,255,0.3)', marginTop: 4 }}>
          Variables: {vars.map((v) => (
            <code key={v} style={{ background: 'rgba(245,158,11,0.15)', color: '#f59e0b', borderRadius: 3, padding: '1px 4px', marginRight: 4 }}>{v}</code>
          ))}
        </div>
      )}
    </BaseNode>
  );
};
